define("_ujgUA_summaryCards", ["jquery", "_ujgUA_config", "_ujgUA_utils"], function($, config, utils) {
    "use strict";

    var CARD_DEFS = [
        { icon: "clock",        label: "Всего часов",    key: "totalHours",   suffix: "ч" },
        { icon: "checkSquare",  label: "Задач",          key: "totalIssues",  suffix: "" },
        { icon: "folderOpen",   label: "Проектов",       key: "totalProjects",suffix: "" },
        { icon: "calendarDays", label: "Дней активн.",   key: "activeDays",   suffix: "" },
        { icon: "trendingUp",   label: "Ø часов/день",   key: "avgHoursPerDay",  suffix: "ч" }
    ];

    function formatHoursCell(hours) {
        var n = hours == null ? 0 : Number(hours);
        if (isNaN(n)) n = 0;
        return (Math.round(n * 10) / 10) + "ч";
    }

    function buildUserStatsTableHtml(userStats) {
        var keys = Object.keys(userStats).sort();
        var rows = "";
        for (var i = 0; i < keys.length; i++) {
            var u = userStats[keys[i]];
            var name = u && u.displayName != null ? String(u.displayName) : keys[i];
            var activeDays = u && u.activeDays != null ? Number(u.activeDays) : 0;
            var daysWithoutWorklogs = u && u.daysWithoutWorklogs != null ? Number(u.daysWithoutWorklogs) : 0;
            var rowClass = daysWithoutWorklogs > 0 ? ' class="ujg-ua-stat-warn"' : "";
            rows +=
                "<tr" + rowClass + ">" +
                "<td>" + utils.escapeHtml(name) + "</td>" +
                "<td>" + formatHoursCell(u && u.totalHours) + "</td>" +
                "<td>" + (isNaN(activeDays) ? 0 : activeDays) + "</td>" +
                "<td>" + (isNaN(daysWithoutWorklogs) ? 0 : daysWithoutWorklogs) + "</td>" +
                "</tr>";
        }
        return (
            '<div class="ujg-ua-user-stats-table">' +
            "<table>" +
            "<tr><th>Пользователь</th><th>Часы</th><th>Активных дней</th><th>Без трудозатрат</th></tr>" +
            rows +
            "</table>" +
            "</div>"
        );
    }

    function create() {
        var $wrap = $('<div class="flex flex-col gap-2"></div>');
        var $grid = $('<div class="grid grid-cols-5 gap-2"></div>');
        $wrap.append($grid);

        function render(data) {
            var html = "";
            for (var i = 0; i < CARD_DEFS.length; i++) {
                var c = CARD_DEFS[i];
                var val = data[c.key];
                if (val == null) val = 0;
                if (typeof val === "number" && val % 1 !== 0) val = Math.round(val * 10) / 10;
                html +=
                    '<div class="dashboard-card px-2.5 py-1.5 flex items-center gap-2">' +
                        utils.icon(c.icon, "w-3.5 h-3.5 text-muted-foreground shrink-0") +
                        '<span class="text-[10px] text-muted-foreground shrink-0">' + utils.escapeHtml(c.label) + '</span>' +
                        '<span class="text-sm font-bold text-foreground ml-auto">' +
                            val + '<span class="text-xs text-muted-foreground">' + c.suffix + '</span>' +
                        '</span>' +
                    '</div>';
            }
            $grid.html(html);

            $wrap.find(".ujg-ua-user-stats-table").remove();
            var us = data.userStats;
            var nUsers = us && typeof us === "object" ? Object.keys(us).length : 0;
            if (nUsers > 1) {
                $wrap.append(buildUserStatsTableHtml(us));
            }
        }

        render({ totalHours: 0, totalIssues: 0, totalProjects: 0, activeDays: 0, avgHoursPerDay: 0 });

        return { $el: $wrap, render: render };
    }

    return { create: create };
});

/* === Module: calendar-heatmap.js === */
define("_ujgUA_calendarHeatmap", ["jquery", "_ujgUA_config", "_ujgUA_utils"], function($, config, utils) {
    "use strict";

    var WEEKDAYS_RU = utils.WEEKDAYS_RU;
    var MONTHS_RU = utils.MONTHS_RU;

    function buildWeeks(dayMap, issueMap, startDate, endDate) {
        var weeks = [];
        var hasSatActivity = false;
        var hasSunActivity = false;

        var d = new Date(startDate);
        var dow = d.getDay();
        var mondayOffset = dow === 0 ? -6 : 1 - dow;
        d.setDate(d.getDate() + mondayOffset);

        while (d <= endDate) {
            var days = [];
            var weekTotal = 0;
            var projectTotals = {};

            for (var i = 0; i < 7; i++) {
                var current = new Date(d);
                current.setDate(d.getDate() + i);
                var dateStr = utils.getDayKey(current);

                if (current >= startDate && current <= endDate) {
                    days.push(dateStr);
                    var dayData = dayMap[dateStr];
                    if (dayData) {
                        weekTotal += dayData.totalHours;
                        if (current.getDay() === 6 && dayData.totalHours > 0) hasSatActivity = true;
                        if (current.getDay() === 0 && dayData.totalHours > 0) hasSunActivity = true;
                        for (var w = 0; w < dayData.worklogs.length; w++) {
                            var wl = dayData.worklogs[w];
                            var issue = issueMap[wl.issueKey];
                            var proj = (issue && issue.project) || "OTHER";
                            projectTotals[proj] = (projectTotals[proj] || 0) + wl.timeSpentHours;
                        }
                    }
                } else {
                    days.push(null);
                }
            }

            var monday = new Date(d);
            var weekLabel = monday.getDate() + " " + MONTHS_RU[monday.getMonth()];

            var pk;
            for (pk in projectTotals) {
                if (projectTotals.hasOwnProperty(pk)) {
                    projectTotals[pk] = Math.round(projectTotals[pk] * 10) / 10;
                }
            }

            weeks.push({
                weekLabel: weekLabel,
                days: days,
                weekTotal: Math.round(weekTotal * 10) / 10,
                projectTotals: projectTotals
            });
            d.setDate(d.getDate() + 7);
        }

        return { weeks: weeks, showSat: hasSatActivity, showSun: hasSunActivity };
    }

    function render(dayMap, issueMap, startDate, endDate) {
        var data = buildWeeks(dayMap, issueMap, startDate, endDate);
        var weeks = data.weeks;
        var showSat = data.showSat;
        var showSun = data.showSun;

        var visibleDays = [0, 1, 2, 3, 4];
        if (showSat) visibleDays.push(5);
        if (showSun) visibleDays.push(6);

        var columnTotals = {};
        var vi, wi, dateStr, dayData;
        for (vi = 0; vi < visibleDays.length; vi++) {
            var dayIdx = visibleDays[vi];
            var sum = 0;
            for (wi = 0; wi < weeks.length; wi++) {
                dateStr = weeks[wi].days[dayIdx];
                if (dateStr) {
                    dayData = dayMap[dateStr];
                    if (dayData) sum += dayData.totalHours;
                }
            }
            columnTotals[dayIdx] = Math.round(sum * 10) / 10;
        }

        var selectedDate = null;
        var selectCallback = null;

        var html = '<div class="dashboard-card p-0 overflow-hidden"><div><table class="w-full table-fixed border-collapse text-[11px]"><colgroup>';
        for (vi = 0; vi < visibleDays.length; vi++) {
            html += "<col />";
        }
        html += '<col style="width:60px;min-width:60px;max-width:60px" />';
        html += "</colgroup><thead><tr class=\"bg-muted/40\">";

        for (vi = 0; vi < visibleDays.length; vi++) {
            dayIdx = visibleDays[vi];
            html += '<th class="text-[10px] font-semibold text-muted-foreground px-1 py-0.5 text-left border-r border-border">' +
                '<div class="flex items-center justify-between"><span>' + WEEKDAYS_RU[dayIdx] + "</span>";
            if (columnTotals[dayIdx] > 0) {
                html += '<span class="text-[9px] font-bold text-foreground/70">' + columnTotals[dayIdx] + "ч</span>";
            }
            html += "</div></th>";
        }
        html += '<th class="text-[10px] font-semibold text-muted-foreground px-1 py-0.5 text-right w-[60px]">Σ</th>';
        html += "</tr></thead><tbody>";

        for (wi = 0; wi < weeks.length; wi++) {
            var week = weeks[wi];
            html += '<tr class="border-t border-border hover:bg-surface-hover/50 align-top">';

            for (vi = 0; vi < visibleDays.length; vi++) {
                dayIdx = visibleDays[vi];
                dateStr = week.days[dayIdx];

                if (!dateStr) {
                    html += '<td class="px-1 py-0.5 border-r border-border bg-muted/10"></td>';
                    continue;
                }

                dayData = dayMap[dateStr];
                var hours = (dayData && dayData.totalHours) || 0;
                var hoverCls = hours > 0 ? "hover:bg-primary/5" : "hover:bg-muted/20";

                html += '<td class="px-1 py-0.5 border-r border-border cursor-pointer transition-colors ' + hoverCls + '" data-date="' + dateStr + '">';
                html += '<div class="flex items-center justify-between mb-0.5">';

                var dtObj = new Date(dateStr + "T00:00:00");
                var dowIdx = (dtObj.getDay() + 6) % 7;
                var dayLabel = WEEKDAYS_RU[dowIdx] + ", " + dtObj.getDate() + " " + MONTHS_RU[dtObj.getMonth()];
                html += '<span class="text-[9px] font-semibold text-muted-foreground">' + utils.escapeHtml(dayLabel) + "</span>";

                if (hours > 0) {
                    var heatCls = utils.getHeatBg(hours);
                    var textCls = hours >= 5 ? "text-primary-foreground" : "text-foreground";
                    html += '<span class="text-[9px] font-bold px-1 py-0 rounded ' + heatCls + " " + textCls + '">' + hours + "ч</span>";
                }
                html += "</div>";

                if (dayData && dayData.worklogs && dayData.worklogs.length > 0) {
                    html += '<div class="space-y-0.5">';
                    for (var wli = 0; wli < dayData.worklogs.length; wli++) {
                        var wl = dayData.worklogs[wli];
                        var issue = issueMap[wl.issueKey];
                        var summary = (issue && issue.summary) || "";
                        html += '<div class="leading-snug"><div class="flex items-baseline gap-1 flex-wrap">' +
                            '<span class="text-[10px] font-semibold text-primary shrink-0">' + utils.escapeHtml(wl.issueKey) + "</span>" +
                            '<span class="text-[9px] text-muted-foreground break-words">' + utils.escapeHtml(summary) + "</span>" +
                            '<span class="text-[9px] font-bold text-foreground shrink-0">' + wl.timeSpentHours + "ч</span>";
                        if (wl.comment) {
                            html += '<span class="text-[9px] text-muted-foreground/80 break-words whitespace-pre-wrap">— ' + utils.escapeHtml(wl.comment) + "</span>";
                        }
                        html += "</div></div>";
                    }
                    html += "</div>";
                }
                html += "</td>";
            }

            var totalCls = week.weekTotal >= 40 ? "text-success" : week.weekTotal >= 20 ? "text-foreground" : "text-muted-foreground";
            html += '<td class="px-1 py-0.5 text-right align-top">';
            html += '<span class="text-[11px] font-bold block ' + totalCls + '">' + week.weekTotal + "ч</span>";

            var projKeys = Object.keys(week.projectTotals);
            if (projKeys.length > 0) {
                projKeys.sort(function(a, b) { return week.projectTotals[b] - week.projectTotals[a]; });
                html += '<div class="mt-0.5 space-y-0">';
                for (var pi = 0; pi < projKeys.length; pi++) {
                    html += '<div class="text-[9px] text-muted-foreground whitespace-nowrap">' +
                        utils.escapeHtml(projKeys[pi]) + ": " + week.projectTotals[projKeys[pi]] + "ч</div>";
                }
                html += "</div>";
            }
            html += "</td></tr>";
        }

        html += "</tbody></table></div></div>";

        var $el = $(html);

        function updateSelection(newDate) {
            $el.find("td[data-date]").removeClass("ring-2 ring-inset ring-primary bg-primary/5");
            if (newDate) {
                $el.find('td[data-date="' + newDate + '"]').addClass("ring-2 ring-inset ring-primary bg-primary/5");
            }
            selectedDate = newDate;
        }

        $el.on("click", "td[data-date]", function() {
            var date = $(this).attr("data-date");
            if (date === selectedDate) {
                updateSelection(null);
                if (selectCallback) selectCallback(null);
            } else {
                updateSelection(date);
                if (selectCallback) selectCallback(date);
            }
        });

        return {
            $el: $el,
            onSelectDate: function(callback) { selectCallback = callback; }
        };
    }

    return { render: render };
});

/* === Module: repo-calendar.js === */
define("_ujgUA_repoCalendar", ["jquery", "_ujgUA_config", "_ujgUA_utils"], function($, config, utils) {
    "use strict";

    var WEEKDAYS_RU = utils.WEEKDAYS_RU;
    var MONTHS_RU = utils.MONTHS_RU;
    var MAX_DAY_ITEMS = 2;
    var MAX_WEEK_REPOS = 3;

    function buildWeeks(repoDayMap, startDate, endDate) {
        var weeks = [];
        var hasSatActivity = false;
        var hasSunActivity = false;
        var d = new Date(startDate);
        var dow = d.getDay();
        var mondayOffset = dow === 0 ? -6 : 1 - dow;

        d.setDate(d.getDate() + mondayOffset);

        while (d <= endDate) {
            var days = [];
            var weekTotal = 0;
            var repoTotals = {};
            var i;

            for (i = 0; i < 7; i++) {
                var current = new Date(d);
                var dateStr;
                var dayData;

                current.setDate(d.getDate() + i);
                dateStr = utils.getDayKey(current);

                if (current >= startDate && current <= endDate) {
                    days.push(dateStr);
                    dayData = repoDayMap[dateStr];
                    if (dayData) {
                        weekTotal += dayData.totalEvents || 0;
                        if (current.getDay() === 6 && dayData.totalEvents > 0) hasSatActivity = true;
                        if (current.getDay() === 0 && dayData.totalEvents > 0) hasSunActivity = true;
                        Object.keys(dayData.countsByRepo || {}).forEach(function(repoName) {
                            repoTotals[repoName] = (repoTotals[repoName] || 0) + (dayData.countsByRepo[repoName] || 0);
                        });
                    }
                } else {
                    days.push(null);
                }
            }

            weeks.push({
                weekLabel: d.getDate() + " " + MONTHS_RU[d.getMonth()],
                days: days,
                weekTotal: weekTotal,
                repoTotals: repoTotals
            });
            d.setDate(d.getDate() + 7);
        }

        return { weeks: weeks, showSat: hasSatActivity, showSun: hasSunActivity };
    }

    function getVisibleDays(showSat, showSun) {
        var visibleDays = [0, 1, 2, 3, 4];
        if (showSat) visibleDays.push(5);
        if (showSun) visibleDays.push(6);
        return visibleDays;
    }

    function getTopRepos(repoTotals) {
        return Object.keys(repoTotals || {}).sort(function(a, b) {
            return repoTotals[b] - repoTotals[a];
        }).slice(0, MAX_WEEK_REPOS);
    }

    function getDayTitle(dateStr) {
        var dt = new Date(dateStr + "T00:00:00");
        var dowIdx = (dt.getDay() + 6) % 7;
        return WEEKDAYS_RU[dowIdx] + ", " + dt.getDate() + " " + MONTHS_RU[dt.getMonth()];
    }

    function getItemText(item) {
        return item.title || item.message || item.hash || item.type || "";
    }

    function getItemTimestamp(item) {
        var ts = item && item.timestamp ? new Date(item.timestamp).getTime() : NaN;
        return isNaN(ts) ? null : ts;
    }

    function getItemInfoScore(item) {
        var score = 0;
        if (item && item.title) score += 3;
        if (item && item.message) score += 2;
        if (item && item.hash) score += 1;
        return score;
    }

    function getSortedDayItems(items) {
        return (items || []).map(function(item, index) {
            return {
                item: item,
                index: index,
                ts: getItemTimestamp(item),
                score: getItemInfoScore(item)
            };
        }).sort(function(a, b) {
            if (a.ts !== null || b.ts !== null) {
                if (a.ts === null) return 1;
                if (b.ts === null) return -1;
                if (a.ts !== b.ts) return b.ts - a.ts;
            }
            if (a.score !== b.score) return b.score - a.score;
            return a.index - b.index;
        }).map(function(entry) {
            return entry.item;
        });
    }

    function renderDayCell(dateStr, dayData) {
        var totalEvents = dayData && dayData.totalEvents || 0;
        var heatCls = utils.getHeatBg(totalEvents);
        var textCls = totalEvents >= 5 ? "text-primary-foreground" : "text-foreground";
        var items = getSortedDayItems(dayData && dayData.items);
        var html = '<td class="px-1 py-0.5 border-r border-border cursor-pointer transition-colors ' +
            (totalEvents > 0 ? "hover:bg-primary/5" : "hover:bg-muted/20") +
            '" data-date="' + dateStr + '">';

        html += '<div class="flex items-center justify-between mb-0.5">';
        html += '<span class="text-[9px] font-semibold text-muted-foreground">' + utils.escapeHtml(getDayTitle(dateStr)) + "</span>";
        if (totalEvents > 0) {
            html += '<span class="text-[9px] font-bold px-1 py-0 rounded ' + heatCls + " " + textCls + '">' + totalEvents + "</span>";
        }
        html += "</div>";

        if (items.length > 0) {
            html += '<div class="space-y-0.5">';
            items.slice(0, MAX_DAY_ITEMS).forEach(function(item) {
                html += '<div class="leading-snug">';
                html += '<div class="text-[10px] font-semibold text-primary break-words">' + utils.escapeHtml(item.repoName || "(unknown)") + "</div>";
                html += '<div class="text-[9px] text-muted-foreground break-words">' + utils.escapeHtml(getItemText(item)) + "</div>";
                html += "</div>";
            });
            if (items.length > MAX_DAY_ITEMS) {
                html += '<div class="text-[9px] font-semibold text-muted-foreground">+' + (items.length - MAX_DAY_ITEMS) + " еще</div>";
            }
            html += "</div>";
        }

        html += "</td>";
        return html;
    }

    function render(repoDayMap, startDate, endDate) {
        var data = buildWeeks(repoDayMap || {}, startDate, endDate);
        var weeks = data.weeks;
        var visibleDays = getVisibleDays(data.showSat, data.showSun);
        var selectedDate = null;
        var selectCallback = null;
        var html = '<div class="dashboard-card p-0 overflow-hidden"><div><table class="w-full table-fixed border-collapse text-[11px]"><colgroup>';
        var vi;

        for (vi = 0; vi < visibleDays.length; vi++) {
            html += "<col />";
        }
        html += '<col style="width:84px;min-width:84px;max-width:84px" />';
        html += '</colgroup><thead><tr class="bg-muted/40">';

        for (vi = 0; vi < visibleDays.length; vi++) {
            var dayIdx = visibleDays[vi];
            html += '<th class="text-[10px] font-semibold text-muted-foreground px-1 py-0.5 text-left border-r border-border">' +
                WEEKDAYS_RU[dayIdx] + "</th>";
        }
        html += '<th class="text-[10px] font-semibold text-muted-foreground px-1 py-0.5 text-right">Σ</th>';
        html += "</tr></thead><tbody>";

        weeks.forEach(function(week) {
            html += '<tr class="border-t border-border hover:bg-surface-hover/50 align-top">';
            visibleDays.forEach(function(dayIdx) {
                var dateStr = week.days[dayIdx];
                if (!dateStr) {
                    html += '<td class="px-1 py-0.5 border-r border-border bg-muted/10"></td>';
                    return;
                }
                html += renderDayCell(dateStr, repoDayMap[dateStr]);
            });

            html += '<td class="px-1 py-0.5 text-right align-top overflow-hidden">';
            html += '<span class="text-[11px] font-bold block">' + week.weekTotal + "</span>";

            getTopRepos(week.repoTotals).forEach(function(repoName) {
                html += '<div class="text-[9px] text-muted-foreground break-all leading-tight text-left">' +
                    utils.escapeHtml(repoName) + ": " + week.repoTotals[repoName] + "</div>";
            });
            html += "</td></tr>";
        });

        html += "</tbody></table></div></div>";

        var $el = $(html);

        function updateSelection(newDate) {
            $el.find("td[data-date]").removeClass("ring-2 ring-inset ring-primary bg-primary/5");
            if (newDate) {
                $el.find('td[data-date="' + newDate + '"]').addClass("ring-2 ring-inset ring-primary bg-primary/5");
            }
            selectedDate = newDate;
        }

        $el.on("click", "td[data-date]", function() {
            var date = $(this).attr("data-date");
            if (date === selectedDate) {
                updateSelection(null);
                if (selectCallback) selectCallback(null);
                return;
            }
            updateSelection(date);
            if (selectCallback) selectCallback(date);
        });

        return {
            $el: $el,
            onSelectDate: function(callback) {
                selectCallback = callback;
            }
        };
    }

    return {
        render: render
    };
});

/* === Module: daily-detail.js === */
define("_ujgUA_dailyDetail", ["jquery", "_ujgUA_config", "_ujgUA_utils"], function($, config, utils) {
    "use strict";

    var MONTHS_FULL_RU = utils.MONTHS_FULL_RU;
    var ICONS = config.ICONS;

    function formatFullDate(dateStr) {
        var d = new Date(dateStr + "T00:00:00");
        return d.getDate() + " " + MONTHS_FULL_RU[d.getMonth()] + " " + d.getFullYear();
    }

    function create() {
        var $el = $('<div class="dashboard-card overflow-hidden" style="display:none"></div>');

        function renderContent(date, dayData, issueMap) {
            var html = '<div class="p-5">' +
                '<div class="flex items-center justify-between mb-4">' +
                    '<h3 class="text-sm font-semibold text-foreground">\uD83D\uDCC5 ' + utils.escapeHtml(formatFullDate(date)) + '</h3>' +
                    '<button class="ujg-ua-detail-close text-muted-foreground hover:text-foreground transition-colors">' +
                        '<span class="w-4 h-4">' + ICONS.x + '</span>' +
                    '</button>' +
                '</div>' +
                '<div class="space-y-2">';

            var issueEntries = {};
            var issueKeys = [];

            if (dayData && dayData.worklogs) {
                for (var i = 0; i < dayData.worklogs.length; i++) {
                    var wl = dayData.worklogs[i];
                    if (!issueEntries[wl.issueKey]) {
                        issueEntries[wl.issueKey] = { hours: 0, changes: [] };
                        issueKeys.push(wl.issueKey);
                    }
                    issueEntries[wl.issueKey].hours += wl.timeSpentHours;
                }
            }

            if (dayData && dayData.changes) {
                for (var c = 0; c < dayData.changes.length; c++) {
                    var ch = dayData.changes[c];
                    if (!issueEntries[ch.issueKey]) {
                        issueEntries[ch.issueKey] = { hours: 0, changes: [] };
                        issueKeys.push(ch.issueKey);
                    }
                    if (ch.field === "status") {
                        issueEntries[ch.issueKey].changes.push({ from: ch.fromString, to: ch.toString });
                    }
                }
            }

            for (var k = 0; k < issueKeys.length; k++) {
                var key = issueKeys[k];
                var entry = issueEntries[key];
                var issue = issueMap[key];
                var summary = (issue && issue.summary) || "";
                var hours = Math.round(entry.hours * 100) / 100;

                html += '<div class="flex items-start gap-3 p-2.5 rounded-lg bg-secondary/50 text-sm">' +
                    '<span class="font-mono text-xs font-semibold text-primary shrink-0 mt-0.5">' + utils.escapeHtml(key) + '</span>' +
                    '<div class="flex-1 min-w-0">' +
                        '<div class="text-foreground font-medium truncate">' + utils.escapeHtml(summary) + '</div>' +
                        '<div class="flex flex-wrap gap-2 mt-1">';

                if (hours > 0) {
                    html += '<span class="inline-flex items-center gap-1 text-xs text-muted-foreground">' +
                        '<span class="w-3 h-3">' + ICONS.clock + '</span> ' + hours + 'ч</span>';
                }

                for (var ci = 0; ci < entry.changes.length; ci++) {
                    var change = entry.changes[ci];
                    html += '<span class="inline-flex items-center gap-1 text-xs text-muted-foreground">' +
                        '<span class="text-warning">' + utils.escapeHtml(change.from) + '</span>' +
                        '<span class="w-3 h-3">' + ICONS.arrowRight + '</span>' +
                        '<span class="text-success">' + utils.escapeHtml(change.to) + '</span></span>';
                }

                html += '</div></div></div>';
            }

            if (issueKeys.length === 0) {
                html += '<div class="text-sm text-muted-foreground text-center py-4">Нет активности за этот день</div>';
            }

            html += '</div></div>';
            return html;
        }

        function show(date, dayData, issueMap) {
            $el.html(renderContent(date, dayData, issueMap)).slideDown(200);
            $el.find(".ujg-ua-detail-close").on("click", function() { hide(); });
        }

        function hide() {
            $el.slideUp(200);
        }

        return { $el: $el, show: show, hide: hide };
    }

    return { create: create };
});

/* === Module: project-breakdown.js === */
define("_ujgUA_projectBreakdown", ["jquery", "_ujgUA_config", "_ujgUA_utils"], function($, config, utils) {
    "use strict";

    var CHART_TEXT = config.CHART_TEXT_COLORS;
    var CHART_BG = config.CHART_COLORS;

    function create() {
        var $el = $('<div class="grid grid-cols-1 lg:grid-cols-2 gap-2"></div>');

        function render(data) {
            var projects = data.projects || [];
            var transitions = data.transitions || [];
            var totalHours = 0;
            for (var i = 0; i < projects.length; i++) totalHours += (projects[i].hours || 0);

            var projHtml =
                '<div class="dashboard-card px-3 py-2">' +
                    '<h3 class="text-[10px] font-semibold text-foreground mb-1.5 uppercase tracking-wider">Проекты</h3>' +
                    '<div class="space-y-1">';

            for (var p = 0; p < projects.length; p++) {
                var proj = projects[p];
                var colorIdx = p % CHART_TEXT.length;
                var pct = totalHours > 0 ? Math.round((proj.hours / totalHours) * 100) : 0;
                projHtml +=
                    '<div class="space-y-0.5">' +
                        '<div class="flex justify-between text-[11px]">' +
                            '<span class="font-semibold ' + CHART_TEXT[colorIdx] + '">' + utils.escapeHtml(proj.key) + '</span>' +
                            '<span class="text-muted-foreground font-mono text-[10px]">' +
                                (Math.round(proj.hours * 10) / 10) + 'ч · ' + proj.count + ' задач' +
                            '</span>' +
                        '</div>' +
                        '<div class="h-1.5 rounded-full bg-secondary overflow-hidden">' +
                            '<div class="h-full rounded-full bg-' + CHART_BG[colorIdx] + '" style="width:' + pct + '%"></div>' +
                        '</div>' +
                    '</div>';
            }

            projHtml += '</div></div>';

            var transHtml =
                '<div class="dashboard-card px-3 py-2">' +
                    '<h3 class="text-[10px] font-semibold text-foreground mb-1.5 uppercase tracking-wider">Переходы статусов</h3>' +
                    '<div class="space-y-0.5">';

            var slice = transitions.slice(0, 8);
            for (var t = 0; t < slice.length; t++) {
                var tr = slice[t];
                transHtml +=
                    '<div class="flex items-center justify-between py-0.5 px-1.5 rounded bg-secondary/30 text-[11px]">' +
                        '<div class="flex items-center gap-1.5">' +
                            '<span class="text-warning text-[10px] font-medium">' + utils.escapeHtml(tr.from) + '</span>' +
                            utils.icon("arrowRight", "w-2.5 h-2.5 text-muted-foreground") +
                            '<span class="text-success text-[10px] font-medium">' + utils.escapeHtml(tr.to) + '</span>' +
                        '</div>' +
                        '<span class="font-mono text-[10px] font-bold text-foreground">' + tr.count + '</span>' +
                    '</div>';
            }

            transHtml += '</div></div>';

            $el.html(projHtml + transHtml);
        }

        render({ projects: [], transitions: [] });

        return { $el: $el, render: render };
    }

    return { create: create };
});

/* === Module: issue-list.js === */
define("_ujgUA_issueList", ["jquery", "_ujgUA_config", "_ujgUA_utils"], function($, config, utils) {
    "use strict";

    var STATUS_COLORS = config.STATUS_COLORS;
    var TYPE_ICONS = config.TYPE_ICONS;

    function create() {
        var expanded = {};

        var $el = $(
            '<div class="dashboard-card px-2 py-1">' +
                '<h3 class="text-[10px] font-semibold text-foreground mb-0.5 uppercase tracking-wider">Задачи</h3>' +
                '<div class="space-y-0 ujg-ua-issue-body"></div>' +
            '</div>'
        );
        var $body = $el.find(".ujg-ua-issue-body");

        function getStatusClasses(status) {
            return STATUS_COLORS[status] || 'bg-muted text-muted-foreground';
        }

        function getTypeIconName(type) {
            return TYPE_ICONS[type] || 'checkCircle2';
        }

        function renderIssue(issue) {
            var iconName = getTypeIconName(issue.type);
            var statusCls = getStatusClasses(issue.status);
            var hours = issue.hours != null ? (Math.round(issue.hours * 10) / 10) : 0;
            return '<div class="flex items-center gap-1.5 py-px px-1 rounded hover:bg-secondary/30 transition-colors text-[11px]">' +
                utils.icon(iconName, "w-3 h-3 text-muted-foreground shrink-0") +
                '<span class="font-mono text-[10px] text-primary font-semibold shrink-0">' + utils.escapeHtml(issue.key) + '</span>' +
                '<span class="truncate flex-1 text-foreground">' + utils.escapeHtml(issue.summary) + '</span>' +
                '<span class="text-[9px] font-medium px-1 py-0 rounded ' + statusCls + '">' + utils.escapeHtml(issue.status) + '</span>' +
                '<span class="flex items-center gap-0.5 text-[10px] text-muted-foreground font-mono shrink-0">' +
                    utils.icon("clock", "w-2.5 h-2.5") + ' ' + hours + 'ч' +
                '</span>' +
            '</div>';
        }

        function render(projects) {
            var html = "";
            for (var i = 0; i < projects.length; i++) {
                var proj = projects[i];
                var isExp = !!expanded[proj.key];
                var chevron = isExp ? "chevronDown" : "chevronRight";
                var hours = proj.hours != null ? (Math.round(proj.hours * 10) / 10) : 0;

                html += '<div>' +
                    '<button class="w-full flex items-center gap-1.5 py-0.5 px-1 rounded hover:bg-secondary/50 transition-colors text-[11px] ujg-ua-proj-toggle" data-key="' + utils.escapeHtml(proj.key) + '">' +
                        utils.icon(chevron, "w-3 h-3 text-muted-foreground shrink-0") +
                        '<span class="font-semibold text-foreground">' + utils.escapeHtml(proj.key) + '</span>' +
                        '<span class="text-muted-foreground text-[10px]">' + proj.count + ' задач · ' + hours + 'ч</span>' +
                    '</button>';

                if (isExp && proj.issues) {
                    html += '<div class="ml-4 space-y-0 pb-0.5">';
                    for (var j = 0; j < proj.issues.length; j++) {
                        html += renderIssue(proj.issues[j]);
                    }
                    html += '</div>';
                }

                html += '</div>';
            }
            $body.html(html);
        }

        $body.on("click", ".ujg-ua-proj-toggle", function() {
            var key = $(this).attr("data-key");
            expanded[key] = !expanded[key];
            render($el.data("projects") || []);
        });

        function renderProjects(projects) {
            $el.data("projects", projects);
            render(projects);
        }

        renderProjects([]);

        return { $el: $el, render: renderProjects };
    }

    return { create: create };
});

